// Parse segmentation
const aiResponse = $input.first().json.content;
let segmentation;

try {
  segmentation = JSON.parse(aiResponse);
} catch (e) {
  segmentation = {
    rfm: { r: 3, f: 3, m: 3 },
    segment: 'Regular',
    tags: ['active'],
    next_campaign: 'nurture',
    priority: 'medium'
  };
}

const order = $input.all()[0].json;
const customer = $input.all()[1]?.json?.[0] || {};

// Calculate lifecycle stage
let lifecycle = 'new';
const orderCount = (customer.order_count || 0) + 1;
if (orderCount > 10) lifecycle = 'champion';
else if (orderCount > 5) lifecycle = 'loyal';
else if (orderCount > 2) lifecycle = 'potential';

// Determine next touchpoint
const nextTouchpoint = new Date();
if (segmentation.segment === 'At Risk') nextTouchpoint.setDate(nextTouchpoint.getDate() + 7);
else if (segmentation.segment === 'Champion') nextTouchpoint.setDate(nextTouchpoint.getDate() + 30);
else nextTouchpoint.setDate(nextTouchpoint.getDate() + 14);

return [{
  json: {
    customer_id: order.customer_id || customer.id,
    email: order.customer_email,
    name: order.customer_name,
    rfm_scores: segmentation.rfm,
    segment: segmentation.segment,
    tags: segmentation.tags,
    lifecycle_stage: lifecycle,
    next_touchpoint: nextTouchpoint.toISOString(),
    recommended_campaign: segmentation.next_campaign,
    priority: segmentation.priority,
    last_order_value: order.order_value,
    total_orders: orderCount,
    updated_at: new Date().toISOString()
  }
}];

